```class Solution {
public:
    long long minimumCost(string s) {
        long long res = 0, ones = 0, zeros = 0;
        for (char c : s) {
            if (c == '1') ones++;
            else zeros++;
        }
        res += abs(ones - zeros);
        for (int i = 0; i < s.size(); i++) {
            if (s[i] == '1') {
                res += i + 1;
                ones--;
            } else {
                res += s.size() - i;
                zeros--;
            }
            if (ones > 0) res += s.size() - i - 1;
            if (zeros > 0) res += i + 1;
        }
        return res;
    }
};```
